(function(global, factory) {
    typeof exports === 'object' && typeof module !== 'undefined' ? module.exports = factory() :
    typeof define === 'function' && define.amd ? define(factory) :
    (global = typeof globalThis !== 'undefined' ? globalThis : global || self, global.emailjs = factory());
})(this, (function() { 'use strict';
    // [ИСПРАВЛЕНО]: Указан абсолютно точный базовый домен официального API EmailJS
    var store = { _userID: null, _origin: 'https://api.emailjs.com' };
    return {
        init: function(publicKey, origin) {
            store._userID = publicKey;
            store._origin = origin || 'https://api.emailjs.com';
        },
        send: function(serviceID, templateID, templateParams, publicKey) {
            var uID = publicKey || store._userID;
            if (!uID) throw 'The user ID is required.';
            
            // [ИСПРАВЛЕНО]: Добавлен обязательный префикс пути /api перед версией /v1.0
            return fetch(store._origin + '/api/v1.0/email/send', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    service_id: serviceID,
                    template_id: templateID,
                    user_id: uID,
                    template_params: templateParams
                })
            }).then(function(response) {
                if (!response.ok) {
                    return response.json().then(function(err) { throw err; });
                }
                return { status: response.status, text: 'OK' };
            });
        }
    };
}));
